use crate::SharedSecret;
use sha3::{Digest, Sha3_256};

pub(crate) const X_WING_LABEL: &[u8] = br"\.//^\";

/// Combines the PQ and traditional shared secrets into a single hybrid
/// [`SharedSecret`] using SHA3-256.
///
/// This follows the hybrid KEM combiner in `hpke-pq.md`. The domain separator
/// `X_WING_LABEL` is appended to bind the context and prevent cross-protocol
/// attacks. The digest is written directly into `SharedSecret` via `new_with`,
/// avoiding an intermediate plaintext stack copy.
pub fn combine_shared_secrets(
    // ss_pq: Shared secret from ML-KEM (post-quantum KEM). This is the
    // output of ML-KEM encapsulation (for the sender) or decapsulation (for
    // the recipient), a 32-byte symmetric key derived from lattice-based
    // cryptography. It provides the main post-quantum security for the
    // hybrid scheme.
    ss_pq: &[u8; 32],
    // ss_t: Shared secret from traditional ECDH (e.g., X25519). This is the
    // result of the ephemeral-static Diffie-Hellman computation between the
    // sender's ephemeral scalar and the recipient's static public key, a
    // 32-byte value that adds classical ECDH security to hedge against
    // weaknesses in ML-KEM.
    ss_t: &[u8; 32],
    // ct_t: Traditional ECDH ciphertext / public share. This is the
    // ephemeral public key generated by the sender during encapsulation (a
    // 32-byte Curve25519 point). The recipient combines this with its static
    // private key to compute ss_t via Diffie-Hellman.
    ct_t: &[u8; 32],
    // ek_t: Recipient's static traditional encapsulation key (that is, the
    // recipient's long-term X25519 public key). It is used by the sender to
    // compute ss_t and is hashed into the combiner output so the derived
    // shared secret is bound to the intended recipient key.
    ek_t: &[u8; 32],
) -> SharedSecret {
    SharedSecret::new_with(|buf| {
        let mut hasher = Sha3_256::new();
        hasher.update(ss_pq);
        hasher.update(ss_t);
        hasher.update(ct_t);
        hasher.update(ek_t);
        hasher.update(X_WING_LABEL);
        buf.copy_from_slice(&hasher.finalize());
    })
}
